var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어이쿠! 빈틈입니다!","JPN":"おっと！　隙あり！","ENG":"Oopsie! I see an opening!","TWN":"嘿！有破綻！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"으랏챠!","JPN":"よっしゃー！","ENG":"Alley-oop!","TWN":"哎喲！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"일부러 보여 준 건데 설렜나 봐?","JPN":"わざとチラ見せしたけど、ときめいちゃった？","ENG":"That was intentional. Were you excited?","TWN":"我是故意露出破綻的啦，你心動了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......그거 아세요? 당신 말투 정말 거슬리네요.","JPN":"……わかってます？　あなたの喋り方、ホント気に障るんですよ。","ENG":"Do you know how annoying you sound when you talk?","TWN":"……妳知道嗎？妳的語氣真的很煩人呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자주 듣던 말인가 보네, 오빠? 이런 게 자기반성이라는 걸까?","JPN":"お兄ちゃんも身に覚えがあるとか？　反省してるのかな？","ENG":"Why, have you heard that often, big brother? This is what people call self-reflection, isn't it?","TWN":"這話我很常聽到呢，哥。這算是自我反省嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 별로 반성할 게 없는 인생을 살아왔는데, 그쪽은 아닌가 보네요.","JPN":"僕にはあまり反省すべきことなんてないですが、そっちは違うみたいですね。","ENG":"I haven't done anything that requires me to reflect on myself. Have you?","TWN":"我的人生沒什麼需要反省的東西，妳看起來倒是有挺多的。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"바로 그런 점이 반성해야 할 부분이 아닐까, 동생?","JPN":"まさにそういうところを改めるべきじゃないの、弟くん？","ENG":"Shouldn't you reflect on yourself about that, little brother?","TWN":"你需要反省的不就是這一點嗎，弟弟？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"동생인지 오빠인지 하나만 하시죠!!","JPN":"弟なのか兄なのか、どっちかに絞ってくれませんかね！！","ENG":"Am I your older or little brother? Make up your mind!","TWN":"到底是弟弟還是哥哥啦！！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"글쎄, 꼭 그래야 하나? 난 욕심쟁이라서 둘 다 하고 싶은데.","JPN":"ふーん、そんな必要ある？　私は欲張りだから、両方がいいな。","ENG":"Should I? I'm greedy. I want both.","TWN":"唉，一定得分清楚嗎？我很貪心不能全都要嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......더는 못 들어주겠군.","JPN":"……聞いてられんな。","ENG":"Argh, I can't take this anymore.","TWN":"……我聽不下去了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주시윤, 비켜.","JPN":"シリュウ、どけ。","ENG":"Shiyoon, move aside.","TWN":"周時雲，走開。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 이번엔 그쪽 차례인가요? 제법 기대되는......","JPN":"ハハ、今度はそっちの番？　こりゃ、楽しみだ……","ENG":"Hah hah. Is it going to be you this time? I can't wait—","TWN":"哈哈，這次輪到妳了嗎？我很期待……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"크흣!","JPN":"くっ！","ENG":"Ugh!","TWN":"唔噗！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"임기응변에 능한 걸 보면 실전 경험이 꽤 많은가 보군.","JPN":"臨機応変に動けるのは実戦の経験が豊富だからだろうな。","ENG":"You must be a veteran soldier, being so good at improvising.","TWN":"臨場反應不錯，看來妳的戰鬥經驗非常豐富。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그래도 아직 한참 부족해.","JPN":"だが、まだ全然足りないぞ。","ENG":"But still not good enough.","TWN":"但還是略嫌不足。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하...... 저도 어디 가서 맞고 다니는 실력은 아닌데......","JPN":"ハハ……私もそう簡単にやられる気はなかったのに……","ENG":"Hah hah... I thought I was pretty good at fighting.","TWN":"哈哈……我的實力也不是很弱，不過……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이건 좀 상상 이상이네요.","JPN":"これは想像を越えましたね。","ENG":"But that was before I met you.","TWN":"這有點超出我的想像呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"시간이라면 제법 끌어 준 거 같은데, 아직도 모자란가?","JPN":"時間稼ぎなら十分にできたと思うが、まだ足りないのか？","ENG":"We've given you enough time. Do you need more?","TWN":"妳已經拖了不少時間了，還不夠嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"더 이상 방해하면 적당히 넘어가 주지 않겠다.","JPN":"これ以上邪魔するなら、ただじゃ済まないぞ。","ENG":"You'll stop interfering with us if you know what's good for you.","TWN":"再礙事的話，我就不會手下留情了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러고 싶긴 하지만...... 저도 나름대로 많은 걸 짊어지고 싸우는 거라서요.","JPN":"そうしたいところですが……私も背負っているものがそこそこ多いので。","ENG":"I'd love to, but I too have got a stake in this fight.","TWN":"雖然我也想這麼做……但我也是背負了不少東西在戰鬥啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러니까 승산이 없다고 하더라도...... 하는 데까지는 해 봐야겠죠?","JPN":"勝算がないとしても……できるとこまではやってみないと。","ENG":"So... even if I don't have a chance to win, I'll have to try as hard as I can.","TWN":"所以就算沒有勝算……我也會撐到最後，總得試試看吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어쩔 수 없군. 그럼 이쪽도 전력으로 상대해주겠다.","JPN":"仕方あるまい。こっちも全力で相手するぞ。","ENG":"Okay, then I'll also do my best to beat you.","TWN":"沒辦法，那我這裡也拿出全力吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님?!","JPN":"師匠！？","ENG":"Master?!","TWN":"師父？！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"저건......?","JPN":"あれは……？","ENG":"That's...","TWN":"那是……？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님......","JPN":"師匠……","ENG":"Master...","TWN":"師父……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":" 들리시나요?!","JPN":"聞こえていますか！？","ENG":" Can you hear me?","TWN":"您聽到了嗎？！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"클리포트 인자 반응이...... 급증했습니다.","JPN":"クリフォト・ファクターの反応が……急増しました。","ENG":"Qliphoth Factor responses have increased.","TWN":"逆卡巴拉因子反應……急速上升。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 일반적인 사냥감들의 반응과는......","JPN":"ただ、通常の獲物からの反応とは……","ENG":"And they're not at all like those","TWN":"但是與一般獵物的反應……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":" 상당히 다릅니다.","JPN":"ずいぶん異なります。","ENG":" from our usual Prey.","TWN":"非常不同。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이건...... 특정 개체의 반응이라기보다는 마치......","JPN":"これは……特定の個体からの反応というよりは、まるで……","ENG":"They're not direct responses from a specific being, either.","TWN":"這……與其說是特定個體的反應，更像……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어딘가 통로를 통해서 조금씩 흘러나오고 있는 것 같습니다.","JPN":"どこかの通路から、少しずつ流れてきているようです。","ENG":"It's as if they're leaking through some kind of passageway.","TWN":"通過某個通道一點點流出的一樣。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쩌면...... 이번 사냥감은 무언가 다른 세계에서 건너오고 있는 걸지도......","JPN":"ひょっとすると……今回の獲物は、どこか別の世界からきているのかもしれません……","ENG":"Maybe this Prey is in the process of coming over from a different world.","TWN":"怎麼可能……這次獵物可能是從另一個世界過來的……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......그렇게 된 거였군.","JPN":"……そういうことか。","ENG":"I see.","TWN":"……原來如此。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 아가씨. 네가 기다리고 있던 게 저거였나?","JPN":"おい、小娘。お前が待っているのはあれのことなのか？","ENG":"Hey, lady. Is that what you've been waiting for?","TWN":"這位小姐。妳在等的是這個嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 그런 것 같네요.","JPN":"ハハ、そうみたいですね。","ENG":"Hah hah. Looks like it is, doesn't it?","TWN":"哈哈，好像是的。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양이 결국 성공했나 보군요.","JPN":"カリンさんがついに成功したみたいです。","ENG":"Karin must have succeeded.","TWN":"看來卡琳小姐終於成功了啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"말을 바꿔서 죄송하지만...... 이제 가보셔도 돼요. 제가 맡은 일은 끝났거든요.","JPN":"手のひらを返すようですみませんが……もう行っていただいて結構ですよ。私の任務はここまでですから。","ENG":"I don't know if it's too late to say this, but you can go now. My job here is done.","TWN":"非常抱歉，我要換種說法了……現在兩位可以過去了。我的工作到此為止。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러니까 혹시 괜찮으시면 저는 살려주시면 안 될까요?","JPN":"ですから、もしよければ私のことは見逃してくれませんか？","ENG":"So... would you be so kind as to let me go alive?","TWN":"所以，如果可以的話，能不能順便放我一條生路？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뻔뻔함만큼은 내 제자와 막상막하로군.","JPN":"そのふてぶてしさ、私の弟子に引けをとらないな。","ENG":"You're just as shameless as my apprentice.","TWN":"厚臉皮的程度和我徒弟不相上下。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아니, 스승님. 아무리 그래도 그 발언은 좀 지나치신 게 아닐까요?","JPN":"師匠。いくらなんでもそれはちょっと言い過ぎでは？","ENG":"Master, even if that's true, did you really have to say it out loud?","TWN":"不，師父，妳不覺得這話有點太過分了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전혀.","JPN":"いや、全然だ。","ENG":"Yes, I did.","TWN":"完全不覺得。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 이제 대충 어떤 일이 벌어지고 있었는지 알 것 같아.","JPN":"とにかく、今何が起こっているかはだいたいわかった気がする。","ENG":"By the way, I think I know what's happening here.","TWN":"不過，我現在大概知道發生什麼事了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너...... <color=#ffd34c>엑자일러</color>였군.","JPN":"お前……<color=#ffd34c>エグザイラー</color>だな。","ENG":"You. You're an <color=#ffd34c>Exile</color>.","TWN":"妳……是<color=#ffd34c>流浪者</color>啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"엑자일러?","JPN":"エグザイラー？","ENG":"An Exile?","TWN":"流浪者？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 가끔씩 너처럼...... 떠밀려 오는 녀석들이 있지.","JPN":"そう、時々お前のような……流れ者がいるんだ。","ENG":"Yes, people like you occasionally drift here by accident.","TWN":"對，偶爾會有像妳一樣……流落到這裡的傢伙。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇지 않고서야 내 제자 같은 놈이 한 세상에 둘이나 있을 리는 없거든.","JPN":"それ以外、私の弟子みたいな奴が同じ世界に二人もいるわけがない。","ENG":"That's the only explanation for your existence in the same world with my apprentice.","TWN":"不然一個世界裡不可能有兩個像我徒弟這樣的傢伙。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 엑자일러들이 어떤 목적을 가지고 오는 일은 드물 텐데......","JPN":"ただ、エグザイラーが特定の目的のために移動してくることは稀だと思うのだが……","ENG":"But Exiles rarely come to places on purpose...","TWN":"不過，流浪者的行動一般很少有什麼目的……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래, 아마 처리 곤란한 뭔가를 이쪽에 떠넘기려고 한 모양이군. 그렇지 않나?","JPN":"何か厄介なものをこの世界に押し付けようとしているんだな、違うか？","ENG":"Ah, I get it. You wanted to dump something here that you couldn't take care of, didn't you?","TWN":"嗯，你們大概是想把那邊的麻煩全推給這邊，對吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......놀랍네요.","JPN":"……こりゃ、たまげた。","ENG":"I'm surprised.","TWN":"……太驚訝了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어떻게 그런 걸 알고 있는 거죠?","JPN":"どうしてそんなことがわかるんです？","ENG":"How do you know that?","TWN":"妳是怎麼知道的？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런 일을 처음 겪은 게 아닌 것 같은데요?","JPN":"こんな経験、初めてじゃないんですね？","ENG":"This isn't the first time you met someone like me, is it?","TWN":"妳好像不是第一次經歷這種事情？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 질문은 사양하지.","JPN":"無駄な質問はよせ。","ENG":"I'm not going to answer irrelevant questions.","TWN":"不要問這種沒建設性的問題。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어차피 차원 통로가 완성된 이상 이쪽으로 넘어오기 전에 저지하는 건 실패로군.","JPN":"どのみち次元間通路が完成したからには、こっち側に渡る前に阻止するのは無理だろうな。","ENG":"Anyway, now that the dimensional passageway is established, our mission to stop the Prey before it arrives has failed.","TWN":"反正次元通道已經完成了，我們阻止向這邊傳送的任務算是失敗了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"미안해요......","JPN":"ごめんなさい……","ENG":"I'm sorry.","TWN":"抱歉……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어떻게 생각할진 모르겠지만 이건 진심입니다.","JPN":"信じてもらえるかわかりませんが、これは本心です。","ENG":"I don't know what you think of me, but I mean it.","TWN":"不知道妳相信不相信，但我是真心的。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무슨 뜻이죠? 저 통로를 넘어오고 있는 존재가 대체 뭐길래요?","JPN":"どういう意味ですか？　あの通路から、何が来ると言うのです？","ENG":"What do you mean? What is it that's coming through that passageway?","TWN":"什麼意思？到底會有什麼通過通道？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저건...... 우리 세계를 거의 멸망 직전까지 몰고 가던 고위 침식체입니다.","JPN":"あれは……私たちの世界を滅亡寸前まで追い込んだ、高位侵食体です。","ENG":"It's... a high-ranking Corrupted Object that pushed our world to the brink of destruction.","TWN":"那是……能將我們的世界推向末日邊緣的高等侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우리는 저 괴물을 막기 위해 모든 수단을 동원했지만......","JPN":"私たちはあの化け物を排除しようと、あらゆる手段をつくしましたが……","ENG":"We did everything in our power to stop that monster.","TWN":"我們為了阻止那個怪物用盡了一切手段……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇게 동원된 전력의 대부분을 희생하고도 그저 움직임을 잠시 멈추는 게 전부였어요.","JPN":"戦力の大半を犠牲にしたにもかかわらず、結果は一時的に動きを止めただけ。","ENG":"It was all we could do, after losing almost every soldier we had, to stop it for a while.","TWN":"就算犧牲了大量戰力，也只是暫時停止了它的活動。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"나와 카린 양의 임무는 놈이 움직이지 못하는 동안 초장거리 차원 통로를 만들어서 아주 먼 이면세계에 놈을 강제로 추방시키는 것입니다.","JPN":"私とカリンさんの任務は、奴が身動きがとれない間、超長距離の次元間通路を作り、\\n遥か遠くの裏世界へ奴を強制追放することです。","ENG":"While it's immobilized, Karin and I are here to create an ultra-distance dimensional passageway and banish it as far into the Counterside as we can.","TWN":"我和卡琳小姐的任務是趁那個傢伙無法行動的時候，開啟一個超長距離的次元通道，將它強制放逐到異界。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우리로서는 최후의 수단이었죠.","JPN":"私たちとしては、これが最後の手段でした。","ENG":"This was the only solution we could think of.","TWN":"這是我們的最後手段。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"원래의 계획대로라면 아무도 살지 않는 초고심도 이면세계에 놈을 추방했어야 하지만......","JPN":"本来の計画通りであれば、誰も存在しない超高深度の裏世界に奴を追いやるつもりでしたが……","ENG":"Originally, we were going to banish that monster into the deepest part of the Counterside where there were no other living things.","TWN":"我們原來的計畫是將它放逐到無人居住的超深異界，但是……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우연인지...... 운명인지...... 이런 이상한 세계에 도착해 버렸네요.","JPN":"偶然なのか……それともこういう運命なのか……この妙な世界に流れ着いてしまいまして。","ENG":"And by accident or by a twist of fate, we've arrived in this strange world instead.","TWN":"也不知道是偶然……還是已經註定的……最後到達了這個奇怪的世界呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우리 세계를 지키기 위해 다른 세계를 희생하는 게 용서받지 못할 일이라는 건 알고 있어요.","JPN":"私たちの世界を守るために別の世界を犠牲にするなんて、許されない行為なのは承知の上です。","ENG":"We know it's not right to sacrifice another world for our own.","TWN":"我知道為了守護我們的世界而犧牲另一個世界是一件無法饒恕的事情。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"비난하시겠다면 얼마든지 받아들일 수......","JPN":"もし私を責めるなら、いくらでも受け入れるつもりで……","ENG":"If you want to criticize, go ahead—","TWN":"如果妳要譴責我，我都會接受……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"특별히 상관없다.","JPN":"別に構わん。","ENG":"I don't care.","TWN":"這沒什麼特別的關係。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......네?","JPN":"……え？","ENG":"Pardon?","TWN":"……什麼？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어차피 우린 놈을 사냥하러 여기에 온 거다.","JPN":"どのみち私たちは、奴を狩りにきてるんだ。","ENG":"We came here to hunt it, anyway.","TWN":"反正我們是為了狩獵才來這裡的。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이런 음모에 휘말린 건 마음에 들지 않지만......","JPN":"そんな企みに巻き込まれたのは本望ではないが……","ENG":"I'm not happy about being swept into this scheme of yours,","TWN":"雖然我不喜歡被捲入這種陰謀中……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"사냥감이 알아서 찾아와 준다면 귀찮은 일을 덜었다고 할 수도 있겠지.","JPN":"獲物が自ら出現してくれるなら、面倒なことが一つ減ったとも言えるだろう。","ENG":"but I can't complain, seeing as it's made my job easier by sending the Prey my way.","TWN":"但獵物如果自己送上門來，那倒是省了不少麻煩。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이봐요 당신, 지금까지 내 말 듣고 있었던 거 맞아요?","JPN":"あのぉ、これまでの私の話、聞いてました？","ENG":"Hey, were you not listening to me?","TWN":"喂，妳聽到我說的話了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저건 우리 세상을 거의 끝장내 버린 괴물이라고요!","JPN":"あれは私たちの世界を滅亡寸前まで追い込んだ化け物なんですよ！","ENG":"That monster all but ended our world!","TWN":"那可是幾乎毀掉我們世界的怪物啊！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그걸 사냥하겠다니, 그런 게 가능했으면 애초에 우리가 이런 짓을 할 이유도 없었다고요!","JPN":"あれに対抗するなんて、それができるならそもそもこんなことしませんから！","ENG":"If it could be hunted, we would have done that instead of trying this!","TWN":"竟然還想著要狩獵，如果能做到的話，我們從一開始就不會做這種事了！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"세상을 끝장내 버릴 괴물이라......","JPN":"世界を滅ぼす化け物か……","ENG":"A monster that all but ended a world.","TWN":"一隻能毀滅世界的怪物……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그것들을 사냥하는 게 내 전문 분야다.","JPN":"そいつらを狩るのが、私の専門分野だ。","ENG":"Hunting things like that is what I do.","TWN":"狩獵它們就是我的專業領域。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};